ch11 = {"c":11,"verses":[
{"v":1,"t":"Quando Roboão chegou a Jerusalém, reuniu cento e oitenta mil guerreiros de Judá e Benjamim para lutar contra Israel e recuperar o reino."},
{"v":2,"t":"Mas o Senhor falou com Semaías, homem de Deus:"},
{"v":3,"t":"'Diga a Roboão, filho de Salomão, rei de Judá, e a todo Israel em Judá e Benjamim:'"},
{"v":4,"t":"'O Senhor diz: Não lutem contra os seus irmãos. Voltem para casa, porque isso veio de mim.' Eles obedeceram ao Senhor e desistiram de lutar contra Jeroboão."},
{"v":5,"t":"Roboão morou em Jerusalém e construiu cidades fortificadas em Judá."},
{"v":6,"t":"Construiu Belém, Etã e Tecoa."},
{"v":7,"t":"Bete-Zur, Socó e Adulão."},
{"v":8,"t":"Gate, Maressa e Zife."},
{"v":9,"t":"Adoraim, Laquis e Azeca."},
{"v":10,"t":"Zorá, Aijalom e Hebrom, cidades fortificadas em Judá e Benjamim."},
{"v":11,"t":"Ele reforçou as fortalezas e colocou comandantes, depósitos de comida, azeite e vinho nelas."},
{"v":12,"t":"Em cada cidade, colocou escudos e lanças. Ele as tornou muito fortes. Judá e Benjamim eram dele."},
{"v":13,"t":"Os sacerdotes e levitas de todo Israel vieram juntar-se a ele."},
{"v":14,"t":"Os levitas deixaram os seus campos e propriedades e vieram para Judá e Jerusalém. Jeroboão e seus filhos os tinham expulsado do serviço ao Senhor."},
{"v":15,"t":"Jeroboão escolheu seus próprios sacerdotes para os lugares altos, para os demônios e para os bezerros que fez."},
{"v":16,"t":"De todas as tribos de Israel, os que queriam buscar o Senhor, Deus de Israel, vieram a Jerusalém para oferecer sacrifícios ao Senhor, Deus dos seus antepassados."},
{"v":17,"t":"Eles fortaleceram o reino de Judá e apoiaram Roboão por três anos. Por três anos eles seguiram o caminho de Davi e Salomão."},
{"v":18,"t":"Roboão casou com Maalate, filha de Jerimote, filho de Davi, e de Abiail, filha de Eliabe, filho de Jessé."},
{"v":19,"t":"Ela deu à luz: Jeús, Samarias e Zaã."},
{"v":20,"t":"Depois casou com Maaca, filha de Absalão. Ela deu à luz: Abias, Atai, Ziza e Selomite."},
{"v":21,"t":"Roboão amava Maaca mais que todas as suas outras esposas. Ele teve dezoito esposas e sessenta outras mulheres, e vinte e oito filhos e sessenta filhas."},
{"v":22,"t":"Roboão fez Abias, filho de Maaca, o líder entre os irmãos, porque queria fazê-lo rei."},
{"v":23,"t":"Roboão agiu com sabedoria. Espalhou alguns dos seus filhos por todas as regiões de Judá e Benjamim, nas cidades fortificadas. Deu-lhes muitos alimentos e arranjou muitas esposas para eles."}
]}
chapters.append(ch11)

# Chapters 12-36 - continuing the translation
chapters.append({"c":12,"verses":[
{"v":1,"t":"Quando o reino de Roboão ficou forte, ele abandonou a lei do Senhor. E todo Israel fez o mesmo."},
{"v":2,"t":"No quinto ano do reinado de Roboão, Sisaque, rei do Egito, atacou Jerusalém, porque eles tinham pecado contra o Senhor."},
{"v":3,"t":"Ele veio com mil e duzentos carros, sessenta mil cavaleiros e soldados incontáveis do Egito: líbios, suquitas e etíopes."},
{"v":4,"t":"Ele conquistou as cidades fortificadas de Judá e chegou até Jerusalém."},
{"v":5,"t":"O profeta Semaías veio a Roboão e aos líderes de Judá que se reuniram em Jerusalém por causa de Sisaque. Ele disse: 'O Senhor diz: Vocês me abandonaram. Por isso eu também entreguei vocês nas mãos de Sisaque.'"},
{"v":6,"t":"Os líderes de Israel e o rei se humilharam e disseram: 'O Senhor é justo.'"},
{"v":7,"t":"Quando o Senhor viu que eles se humilharam, ele falou com Semaías: 'Eles se humilharam. Eu não os destruirei. Em breve darei a eles algum livramento. Não derramarei a minha ira sobre Jerusalém pela mão de Sisaque.'"},
{"v":8,"t":"'Porém eles serão servos dele. Assim aprenderão a diferença entre me servir e servir aos reinos da terra.'"},
{"v":9,"t":"Sisaque, rei do Egito, atacou Jerusalém e levou os tesouros do templo e do palácio. Levou tudo, inclusive os escudos de ouro que Salomão tinha feito."},
{"v":10,"t":"O rei Roboão fez escudos de bronze para substituí-los e os entregou aos guardas da porta do palácio."},
{"v":11,"t":"Sempre que o rei ia ao templo, os guardas os levavam. Depois os devolviam ao depósito."},
{"v":12,"t":"Porque Roboão se humilhou, a ira do Senhor se afastou dele e não o destruiu completamente. Em Judá ainda havia coisas boas."},
{"v":13,"t":"O rei Roboão se fortaleceu em Jerusalém e reinou. Tinha quarenta e um anos quando começou a reinar. Reinou dezessete anos em Jerusalém, a cidade que o Senhor escolheu para colocar o seu nome. A mãe dele se chamava Naamá, e era amonita."},
{"v":14,"t":"Ele fez o mal, porque não buscou ao Senhor de coração."},
{"v":15,"t":"Os fatos do reinado de Roboão, do começo ao fim, estão nos registros do profeta Semaías e do profeta Ido. Houve guerras entre Roboão e Jeroboão o tempo todo."},
{"v":16,"t":"Roboão morreu e foi sepultado na cidade de Davi. Abias, seu filho, reinou no lugar dele."}
]})

# Chapters 13-36 - I'll generate these more concisely but still accurately
chapters.append({"c":13,"verses":[
{"v":1,"t":"No décimo oitavo ano do rei Jeroboão, Abias começou a reinar sobre Judá."},
{"v":2,"t":"Ele reinou três anos em Jerusalém. Sua mãe se chamava Micaía, filha de Uriel, de Gibeá. Houve guerra entre Abias e Jeroboão."},
{"v":3,"t":"Abias entrou na batalha com quatrocentos mil guerreiros escolhidos. Jeroboão se posicionou com oitocentos mil guerreiros fortes."},
{"v":4,"t":"Abias ficou de pé no monte Zemaraim, nas montanhas de Efraim, e disse: 'Ouçam-me, Jeroboão e todo Israel!'"},
{"v":5,"t":"'Vocês não sabem que o Senhor, Deus de Israel, deu o reino de Israel a Davi e seus filhos para sempre, por uma aliança que não se quebra?'"},
{"v":6,"t":"'Mas Jeroboão, filho de Nebate, servo de Salomão, se rebelou contra o seu senhor.'"},
{"v":7,"t":"'Homens sem valor se juntaram a ele e desafiaram Roboão, filho de Salomão. Roboão era jovem e inexperiente e não conseguiu resistir a eles.'"},
{"v":8,"t":"'Agora vocês acham que podem resistir ao reino do Senhor, que está nas mãos dos filhos de Davi? Vocês são uma multidão enorme e têm com vocês os bezerros de ouro que Jeroboão fez como deuses.'"},
{"v":9,"t":"'Vocês expulsaram os sacerdotes do Senhor, os filhos de Arão, e os levitas! Vocês fizeram sacerdotes como os povos de outras terras! Qualquer um que traz um novilho e sete carneiros vira sacerdote dos seus falsos deuses.'"},
{"v":10,"t":"'Mas para nós, o Senhor é o nosso Deus. Nós não o abandonamos. Os sacerdotes que servem ao Senhor são filhos de Arão. Os levitas fazem o trabalho deles.'"},
{"v":11,"t":"'Eles oferecem ao Senhor sacrifícios e incenso todas as manhãs e tardes. Eles cuidam dos pães sagrados na mesa pura e acendem o candelabro de ouro todas as tardes. Nós guardamos o serviço do Senhor nosso Deus. Mas vocês o abandonaram.'"},
{"v":12,"t":"'Deus está conosco como nosso líder! Os seus sacerdotes estão prontos para tocar as trombetas contra vocês. Israelitas, não lutem contra o Senhor, Deus dos seus antepassados! Vocês não vão vencer.'"},
{"v":13,"t":"Mas Jeroboão mandou soldados fazerem uma emboscada por trás. Judá estava cercado pela frente e por trás."},
{"v":14,"t":"Judá olhou e viu que a batalha vinha dos dois lados. Então clamaram ao Senhor. Os sacerdotes tocaram as trombetas."},
{"v":15,"t":"Os homens de Judá gritaram. Quando gritaram, Deus derrotou Jeroboão e todo Israel diante de Abias e Judá."},
{"v":16,"t":"Os israelitas fugiram de Judá. Deus os entregou nas mãos de Judá."},
{"v":17,"t":"Abias e seu povo causaram uma grande derrota. Quinhentos mil guerreiros escolhidos de Israel morreram."},
{"v":18,"t":"Os israelitas foram humilhados. Judá venceu porque confiou no Senhor, Deus dos seus antepassados."},
{"v":19,"t":"Abias perseguiu Jeroboão e tomou dele as cidades de Betel, Jesana e Efrom, com as vilas ao redor."},
{"v":20,"t":"Jeroboão nunca mais recuperou o seu poder no tempo de Abias. O Senhor o feriu e ele morreu."},
{"v":21,"t":"Abias ficou forte. Casou com catorze mulheres e teve vinte e dois filhos e dezesseis filhas."},
{"v":22,"t":"Os outros fatos sobre Abias estão escritos nos registros do profeta Ido."}
]})

